private List<CellInfo> getDisplayedAddressFields(Report report, NUIForm form) {
	List<CellInfo> addressFields = new ArrayList<>();
    if(!report.isValue("displayedFields")) {
        addressFields = new MapReportHelper().getAddressFields(form);
    } else {
        try {
            JSONArray displayedFields = new JSONArray(report.getValue("displayedFields"));
            for(int i = 0; i < displayedFields.length(); i++) {
                int domainId = displayedFields.optInt(i, Const.NODOMAIN);
                if(domainId == Const.NODOMAIN) continue;
                CellInfo cell = form.getCellInfoByDomainId(domainId);
                if(cell == null) continue;
                addressFields.add(cell);
            }
        } catch(Exception ignored) {
        }
    }
    return addressFields;
}

private List<CellInfo> getDisplayedSelectFields(Report report, NUIForm form) {
    List<CellInfo> selectFields = new ArrayList<>();
    if(!report.isValue("displayedSelectFields")) {
        selectFields.add(form.getAllFields(true).get(0));
    } else {
        try {
            JSONArray displayedFields = new JSONArray(report.getValue("displayedSelectFields"));
            for(int i = 0; i < displayedFields.length(); i++) {
                int domainId = displayedFields.optInt(i, Const.NODOMAIN);
                if(domainId == Const.NODOMAIN) continue;
                CellInfo cell = form.getCellInfoByDomainId(domainId);
                if(cell == null) continue;
                selectFields.add(cell);
            }
        } catch(Exception ignored) {
        }
    }
    return selectFields;
}


private String createAddressRuleSelectItem(AddressRuleSetting addressRule, List<CellInfo> allAddressFields, List<CellInfo> selectFields, RagicBundle bundle, int index) {

    StringBuilder sb = new StringBuilder();

    sb.append("<div style='margin:0 0 15px 10px' class='MapSelectItem' id='addressRule"+index+"'>");
    // Create select for adress
    sb.append("<select title='"+bundle.getString("mapReport_addressTitle")+"' class='addressSelect' style='width:100px' onchange='updateAddressResult(this)'>");
    sb.append(this.createFieldsOptions( addressRule.getAddress()!=null?addressRule.getAddress().getDomainId():-1, allAddressFields));
    sb.append("</select>");
    // Create select for display(origin from mapReport)
    sb.append( "<a href='javascript:void(0)' title='"+bundle.getString("mapReport_displayedTitle")+"'class='displayedSelect' onclick='selectDisplayedFields(this)' style='margin-left:20px;'>"+bundle.getString("labelField") );

    if(addressRule.getDisplayedField()!=null){
       //show what you select

        String selectText=" ";
        for(CellInfo cell:addressRule.getDisplayedField()){
            selectText=selectText+cell.getValue()+"、";
        }
        selectText=selectText.substring(0, selectText.length()-1);
        sb.append(selectText);

    }

    sb.append( "</a>");
    // Create removeButton
    sb.append("<div style='display:inline;cursor:pointer;margin:10px;' onclick='removeAddressRuleSelectItem(this)'>");
    sb.append("    <i class='fa fa-times' style='color:#555;cursor:pointer;'></i>");
    sb.append("</div>");
    sb.append("</div>");

    return sb.toString();
}

private String createFieldsOptions(int selectedField, List<CellInfo> Fields) {
    StringBuilder sb = new StringBuilder();
    sb.append("<option value='-1'></option>");
    for(CellInfo info: Fields) {
        if(info==null) continue;
        int domainId = info.getDomainId();
        sb.append("<option");
        sb.append(" value='").append(domainId).append("'");
        if(selectedField != -1 && selectedField == domainId) sb.append("selected");
        sb.append(">").append(info.getValue()).append("</option>");
    }
    return sb.toString();
}


